operation.add:
// ── Content Blocks Pro ──────────────────────────────────────────
$data['tab_content_blocks'] = 'Content Blocks';
if ($this->config->get('module_oc_kit_content_blocks_status')) {
    try {
        $data['cb_form_html'] = $this->load->controller(
            'extension/module/oc_kit_content_blocks/form',
            ['route' => 'catalog/product', 'page_id' => isset($this->request->get['product_id']) ? (int)$this->request->get['product_id'] : 0]
        );
    } catch (\Throwable $e) {
        $data['cb_form_html'] = '';
    }
} else {
    $data['cb_form_html'] = '';
}
// ── /Content Blocks Pro ─────────────────────────────────────────

// ── Content Blocks Pro: save blocks ─────────────────────────────
if ($this->config->get('module_oc_kit_content_blocks_status') && isset($this->request->post['cb_blocks_json'])) {
    try {
        $this->load->model('extension/module/oc_kit_content_blocks');
        $cbBlocks = json_decode($this->request->post['cb_blocks_json'], true);
        if (is_array($cbBlocks)) {
            $productId = isset($this->request->get['product_id']) ? (int)$this->request->get['product_id'] : (int)$this->db->getLastId();
            $this->model_extension_module_oc_kit_content_blocks->saveBlocks([
                'page_route' => 'catalog/product',
                'page_id'    => $productId,
                'blocks'     => $cbBlocks,
            ]);
        }
    } catch (\Throwable $e) { /* silent */ }
}
// ── /Content Blocks Pro ─────────────────────────────────────────

// ── Content Blocks Pro: delete page blocks ───────────────────────
if ($this->config->get('module_oc_kit_content_blocks_status')) {
    try {
        $this->load->model('extension/module/oc_kit_content_blocks');
        $this->model_extension_module_oc_kit_content_blocks->removePageBlocks('catalog/product', (int)$product_id);
    } catch (\Throwable $e) { /* silent */ }
}
// ── /Content Blocks Pro ─────────────────────────────────────────

