// ── Content Blocks Pro: shortcode [cb block_id=X] ────────────────
if ($this->config->get('module_oc_kit_content_blocks_status') && strpos($data['description'], '[cb ') !== false) {
    try {
        // Strip <p> wrapping shortcodes
        $data['description'] = preg_replace('/<p[^>]*>\s*(\[cb\s[^\]]+\])\s*<\/p>/i', '$1', $data['description']);
        // Render shortcodes
        $data['description'] = preg_replace_callback(
            '/\[cb\s+block_id=(\d+)([^\]]*)\]/i',
            function ($m) {
                try {
                    return $this->load->controller(
                        'extension/module/oc_kit_content_blocks/render',
                        ['block_id' => (int)$m[1]]
                    );
                } catch (\Throwable $e) { return ''; }
            },
            $data['description']
        );
    } catch (\Throwable $e) { /* silent */ }
}
// ── /Content Blocks Pro ─────────────────────────────────────────

if ($this->config->get('module_oc_kit_content_blocks_status') && strpos($data['description'], '[cb ') !== false) {
    try {
        $data['description'] = preg_replace('/<p[^>]*>\s*(\[cb\s[^\]]+\])\s*<\/p>/i', '$1', $data['description']);
        $cbCtrl = $this;
        $data['description'] = preg_replace_callback(
            '/\[cb\s+block_id=(\d+)([^\]]*)\]/i',
            function ($m) use ($cbCtrl) {
                try {
                    return $cbCtrl->load->controller('extension/module/oc_kit_content_blocks/render', ['block_id' => (int)$m[1]]);
                } catch (\Throwable $e) {
                    return '';
                }
            },
            $data['description']
        );
    } catch (\Throwable $e) { /* shortcode render skipped */ }
}

if ($this->config->get('module_oc_kit_content_blocks_status') && strpos($data['description'], '[cb ') !== false) {
