            },
            $data['description']
        );
    } catch (\Throwable $e) { /* shortcode render skipped */ }
}

// ── Content Blocks Pro: global blocks for Twig templates ─────────
if ($this->config->get('module_oc_kit_content_blocks_status')) {
    try {
        $this->load->model('extension/module/oc_kit_content_blocks');
        $data['cb_blocks'] = [];
        foreach ($this->model_extension_module_oc_kit_content_blocks->getGlobalBlocks() as $gb) {
            $bid = (int)($gb['block_id'] ?? 0);
            if ($bid) {
                try { $data['cb_blocks'][$bid] = $this->load->controller('extension/module/oc_kit_content_blocks/render', ['block_id' => $bid]); }
                catch (\Throwable $e) { $data['cb_blocks'][$bid] = ''; }
            }
        }
    } catch (\Throwable $e) { $data['cb_blocks'] = []; }
}
